## Sketch 2 · Relés SPDT (mismo código que C3 y C6)

```cpp
int relays[] = {D0, D2, D8, D10};

void setup() {
    Serial.begin(115200);
    for (int r : relays) pinMode(r, OUTPUT);
}

void loop() {
    for (int r : relays) {
        digitalWrite(r, HIGH);
        Serial.printf("Relay %d ON\n", r);
        delay(500);
        digitalWrite(r, LOW);
        delay(500);
    }
}
